  phone: "M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.07 9.81a19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 3 1h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z",
  map: "M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0zM12 7a3 3 0 1 0 0 6 3 3 0 0 0 0-6z",
  camera: "M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2zM12 17a4 4 0 1 0 0-8 4 4 0 0 0 0 8z",
  github: "M12 2C6.48 2 2 6.48 2 12c0 4.42 2.87 8.17 6.84 9.5.5.08.66-.23.66-.5v-1.69c-2.77.6-3.36-1.34-3.36-1.34-.46-1.16-1.11-1.47-1.11-1.47-.91-.62.07-.6.07-.6 1 .07 1.53 1.03 1.53 1.03.87 1.52 2.34 1.07 2.91.83.09-.65.35-1.09.63-1.34-2.22-.25-4.55-1.11-4.55-4.92 0-1.11.38-2 1.03-2.71-.1-.25-.45-1.29.1-2.64 0 0 .84-.27 2.75 1.02.79-.22 1.65-.33 2.5-.33.85 0 1.71.11 2.5.33 1.91-1.29 2.75-1.02 2.75-1.02.55 1.35.2 2.39.1 2.64.65.71 1.03 1.6 1.03 2.71 0 3.82-2.34 4.66-4.57 4.91.36.31.69.92.69 1.85V21c0 .27.16.59.67.5C19.14 20.16 22 16.42 22 12A10 10 0 0 0 12 2z",
  link: "M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71",
  plus: "M12 5v14M5 12h14",
  eye: "M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8zM12 9a3 3 0 1 0 0 6 3 3 0 0 0 0-6z",
  grad: "M22 10v6M2 10l10-5 10 5-10 5z",
  check: "M20 6L9 17l-5-5",
  up: "M18 15l-6-6-6 6",
  code: "M16 18l6-6-6-6M8 6l-6 6 6 6",
  layout: "M12 2H2v10h10V2zM22 2h-8v6h8V2zM22 12h-8v10h8V12zM12 16H2v6h10v-6z",
  zap: "M13 2L3 14h9l-1 8 10-12h-9l1-8z",
  award: "M12 15l-4.74 2.49 1.7-5.38L5 8.49l5.52-.27L12 3l1.48 5.22 5.52.27-3.96 3.62 1.7 5.38L12 15z",
  star: "M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z",
};

// ---- DATA ----
const navLinks = [
  { label: 'Home', href: '#home' },
  { label: 'Services', href: '#services' },
  { label: 'About', href: '#about' },
  { label: 'Projects', href: '#projects' },
  { label: 'Experience', href: '#experience' },
  { label: 'Contact', href: '#contact' },
];

const services = [
  { icon: ICONS.layout, title: 'Frontend Development', desc: 'Developing modern, responsive, and interactive web applications using React.js, JavaScript, HTML5, CSS3, and Bootstrap.' },
  { icon: ICONS.zap, title: 'UI/UX Design', desc: 'Designing clean, intuitive, and user-friendly interfaces that provide seamless user experiences across all devices.' },
  { icon: ICONS.code, title: 'React.js Development', desc: 'Creating reusable React components, state management solutions, dynamic interfaces, and scalable frontend architectures.' },
  { icon: ICONS.link, title: 'API Integration', desc: 'Connecting frontend applications with RESTful APIs, authentication systems, and third-party services efficiently.' },
  { icon: ICONS.eye, title: 'Responsive Design', desc: 'Building websites optimized for desktop, tablet, and mobile devices using modern responsive design techniques.' },
  { icon: ICONS.star, title: 'Performance Optimization', desc: 'Improving website performance, accessibility, responsiveness, and overall user experience for better results.' },
];

const skills = [
  {
    cat: 'Programming Languages',
    items: ['JavaScript (ES6+)', 'TypeScript', 'HTML5', 'CSS3', 'Node.js'],
  },
  {
    cat: 'Frontend Technologies',
    items: ['React.js', 'Bootstrap', 'Responsive Web Design', 'Component-Based Dev', 'SPA Development'],
  },
  {
    cat: 'Backend & Database',
    items: ['Node.js', 'MongoDB', 'Express.js', 'REST APIs', 'Authentication Systems'],
  },
  {
    cat: 'UI/UX',
    items: ['Wireframing', 'Responsive Design', 'User Interface Design', 'UX Principles', 'Prototyping', 'Design Systems'],
  },
  {
    cat: 'Tools & Platforms',
    items: ['Git', 'GitHub', 'VS Code', 'Nodemailer', 'OpenAI APIs', 'Llama 3'],
  },
];

const projects = [
  {
    id: 1,
    title: 'Intelligent Tourism Platform',
    subtitle: 'Full Stack AI-Powered Tourism Management System',
    desc: 'An intelligent tourism platform developed as a final-year project that helps travelers discover destinations, receive AI-powered recommendations, and manage tour bookings.',
    tags: ['React.js', 'Node.js', 'MongoDB', 'OpenAI', 'Express.js'],
    featured: true,
    features: ['AI Recommendations', 'NLP Chatbot', 'OpenAI Integration', 'Llama 3 Chatbot', 'Role-Based Auth', 'Email Verification', 'Live Weather Forecast', 'Tour Booking', 'Payment Integration', 'Admin Dashboard', 'Responsive UI', 'REST APIs'],
    fullDesc: 'An intelligent tourism platform developed as a final-year project that helps travelers discover destinations, receive AI-powered recommendations, explore tourist attractions, and manage tour bookings through a modern web application. The platform includes secure authentication, role-based dashboards, AI chatbot integration, weather forecasting, payment processing, email notifications, and comprehensive tour management features.',
  },
];

const experience = [
  {
    period: 'June 2026',
    role: 'Frontend Developer Intern',
    company: 'Reverse4K × International Islamic University Islamabad',
    desc: 'Worked on modern web development projects while collaborating with experienced developers. Gained practical industry experience in frontend development, deployment workflows, responsive design implementation, and software development best practices.',
  },
  {
    period: 'January 2024 – June 2024',
    role: 'Web Development Trainee',
    company: 'National Freelancing Training Program (NFTP)',
    desc: 'Successfully completed an intensive web development training program covering frontend and full-stack development concepts. Acquired practical experience in HTML5, CSS3, JavaScript, React.js, Bootstrap, Tailwind CSS, and WordPress.',
  },
];

const education = [
  {
    icon: ICONS.grad,
    period: '2022 – 2026',
    degree: 'Bachelor of Information Technology',
    school: 'International Islamic University Islamabad',
    desc: 'Completing a Bachelor\'s degree in IT with focus on software engineering, web development, database systems, networking, cybersecurity, and modern application development.',
  },
  {
    icon: ICONS.award,
    period: '2019 – 2021',
    degree: 'Higher Secondary School Certificate (Pre-Medical)',
    school: 'Punjab Girls College Rawalakot, AJK',
    desc: 'Completed pre-medical studies before transitioning into Information Technology, demonstrating adaptability and a strong passion for technology.',
  },
];

const certs = [
  { name: 'Certificate of Completion – Web Development Track', org: 'National Freelancing Training Program (NFTP)' },
  { name: 'Certificate of Appreciation', org: 'CosmiCode Coding Quiz Competition' },
  { name: 'Web Development Internship Certificate', org: 'Reverse4K × IIUI' },
];

const marqueeItems = ['React.js', 'JavaScript', 'TypeScript', 'UI/UX Design', 'Node.js', 'MongoDB', 'REST APIs', 'Responsive Design', 'Bootstrap', 'Git & GitHub'];

// ---- HELPER: image uploader ----
function useImageUpload(initial = null) {
  const [img, setImg] = useState(initial);
  const ref = useRef();
  const open = () => ref.current && ref.current.click();
  const onChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => setImg(ev.target.result);
    reader.readAsDataURL(file);
  };
  return { img, ref, open, onChange };
}

// ---- NAVBAR ----
function Navbar({ dark, toggleDark, activeSection }) {
  const [open, setOpen] = useState(false);
  return (
    <>
      <nav className="navbar">
        <div className="nav-inner">
          <div className="nav-logo">UZ</div>
          <div className="nav-links">
            {navLinks.map(l => (
              <a key={l.label} href={l.href} className={activeSection === l.href.slice(1) ? 'active' : ''} onClick={() => setOpen(false)}>
                {l.label}
              </a>
            ))}
          </div>
          <div className="nav-right">
            <button className="theme-toggle" onClick={toggleDark} title="Toggle theme">
              {dark
                ? <Icon d={ICONS.sun} size={17} />
                : <Icon d={ICONS.moon} size={17} />}
            </button>
            <a href="#contact" className="nav-contact-btn" style={{ display: 'none' }}>Contact Me</a>
            <button className="hamburger" onClick={() => setOpen(o => !o)} aria-label="Menu" style={{ display: 'flex' }}>
              {open
                ? <><span /><span /><span /></>
                : <><span /><span /><span /></>}
            </button>
          </div>
        </div>
      </nav>
      <div className={`mobile-menu${open ? ' open' : ''}`}>
        {navLinks.map(l => (
          <a key={l.label} href={l.href} onClick={() => setOpen(false)}>{l.label}</a>
        ))}
        <a href="mailto:urwazareef4@gmail.com" className="btn btn-accent" style={{ marginTop: 8, justifyContent: 'center' }}>Contact Me</a>
      </div>
    </>
  );
}

// ---- HERO ----
function Hero({ heroImg }) {
  const [typed, setTyped] = useState('');
  const titles = ['Frontend Developer', 'React.js Developer', 'UI/UX Designer'];
  const titleRef = useRef(0);
  const charRef = useRef(0);
  const deleting = useRef(false);

  useEffect(() => {
    const tick = () => {
      const current = titles[titleRef.current];
      if (!deleting.current) {
        setTyped(current.slice(0, charRef.current + 1));
        charRef.current++;
        if (charRef.current === current.length) { deleting.current = true; return 2000; }
      } else {
        setTyped(current.slice(0, charRef.current - 1));
        charRef.current--;
        if (charRef.current === 0) {
          deleting.current = false;
          titleRef.current = (titleRef.current + 1) % titles.length;
          return 400;
        }
      }
      return deleting.current ? 60 : 90;
    };
    let timeout;
    const run = () => { const delay = tick(); timeout = setTimeout(run, delay); };
    timeout = setTimeout(run, 800);
    return () => clearTimeout(timeout);
  }, []);

  return (
    <section id="home" className="hero">
      <div className="container">
        <div className="hero-inner">
          <div className="hero-content">
            <div className="hero-greeting">
              <span>👋</span> Hello There!
            </div>
            <h1 className="hero-name">
              I'm <em>Urwa Zareef,</em>
            </h1>
            <div className="hero-title">
              {typed}<span style={{ color: 'var(--accent)', fontWeight: 700, animation: 'blink 1s step-end infinite' }}>|</span>
            </div>
            <p className="hero-desc">
              I'm a passionate Frontend Developer and UI/UX Designer specializing in creating responsive, interactive, and user-friendly web applications. With expertise in React.js, JavaScript, TypeScript, and modern frontend technologies, I transform ideas into scalable digital products.
            </p>
            <div className="hero-btns">
              <button className="btn btn-accent" onClick={() => window.open('mailto:urwazareef4@gmail.com')}>
                <Icon d={ICONS.mail} size={16} /> Contact Me
              </button>
              <a href="#projects" className="btn btn-outline">
                View My Work <Icon d={ICONS.arrow} size={16} />
              </a>
              <button className="btn btn-primary" onClick={heroImg.open}>
                <Icon d={ICONS.download} size={16} /> Download Resume
              </button>
            </div>
            <div className="hero-stats">
              <div className="stat"><span className="stat-num">05<span>+</span></span><span className="stat-label">Projects Done</span></div>
              <div className="stat"><span className="stat-num">15<span>+</span></span><span className="stat-label">Technologies</span></div>
              <div className="stat"><span className="stat-num">03<span>+</span></span><span className="stat-label">Certificates</span></div>
              <div className="stat"><span className="stat-num">01<span>+</span></span><span className="stat-label">Internships</span></div>
            </div>
          </div>
          <div className="hero-visual">
            <div className="hero-img-wrap">
              <div className="hero-badge badge-1">
                <span style={{ color: 'var(--accent)', marginRight: 6 }}>✦</span> UI/UX Designer
              </div>
              <div className="hero-img-circle">
                {heroImg.img
                  ? <img src={heroImg.img} alt="Urwa Zareef" />
                  : (
                    <div className="hero-img-placeholder" onClick={heroImg.open}>
                      <Icon d={ICONS.camera} size={36} />
                      <p>Click to upload your photo</p>
                    </div>
                  )}
              </div>
              <div className="hero-badge badge-2 badge-accent">
                <span style={{ marginRight: 4 }}>⚡</span> Product Designer
              </div>
              <button className="upload-btn-hero" onClick={heroImg.open}>
                <Icon d={ICONS.camera} size={14} />
                {heroImg.img ? 'Change Photo' : 'Upload Photo'}
              </button>
            </div>
            <input type="file" accept="image/*" className="hidden-input" ref={heroImg.ref} onChange={heroImg.onChange} />
          </div>
        </div>
      </div>
      <style>{`@keyframes blink { 50% { opacity: 0; } }`}</style>
    </section>
  );
}

// ---- SKILLS MARQUEE ----
function Marquee() {
  const doubled = [...marqueeItems, ...marqueeItems];
  return (
    <div className="skills-marquee">
      <div className="marquee-track">
        {doubled.map((item, i) => (
          <span key={i} className="marquee-item">
            {item}
            <span className="marquee-dot">✦</span>
          </span>
        ))}
      </div>
    </div>
  );
}

// ---- SERVICES ----
function Services() {
  return (
    <section id="services" className="section">
      <div className="container">
        <div className="section-label">Services</div>
        <h2 className="section-heading">
          Services <span className="display">I Provide</span>
        </h2>
        <div className="services-grid">
          {services.map((s, i) => (
            <div key={i} className="service-card">
              <div className="service-icon"><Icon d={s.icon} size={22} /></div>
              <h3>{s.title}</h3>
              <p>{s.desc}</p>
              <div className="service-link">Learn more <Icon d={ICONS.arrow} size={14} /></div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

// ---- ABOUT ----
function About({ aboutImg }) {
  return (
    <section id="about" className="section section-alt">
      <div className="container">
        <div className="about-grid">
          <div className="about-img-wrap">
            <div className="about-img-frame">
              {aboutImg.img
                ? <img src={aboutImg.img} alt="About Urwa" />
                : (
                  <div className="about-img-placeholder" onClick={aboutImg.open}>
                    <Icon d={ICONS.camera} size={40} />
                    <p>Click to upload your photo</p>
                  </div>
                )}
              <button className="upload-btn-about" onClick={aboutImg.open}>
                <Icon d={ICONS.camera} size={13} />
                {aboutImg.img ? 'Change' : 'Upload Photo'}
              </button>
            </div>
            <input type="file" accept="image/*" className="hidden-input" ref={aboutImg.ref} onChange={aboutImg.onChange} />
            <div className="about-stat-card card2">
              <div className="num">05+</div>
              <div className="lbl">Projects Completed</div>
            </div>
            <div className="about-stat-card card1">
              <div className="num">15+</div>
              <div className="lbl">Technologies</div>
            </div>
          </div>
          <div className="about-content">
            <div>
              <div className="section-label">About Me</div>
              <h2 className="section-heading" style={{ marginBottom: 20 }}>
                Who is <span className="display">Urwa Zareef?</span>
              </h2>
            </div>
            <p>
              Hi, I'm <strong>Urwa Zareef</strong>, a Frontend Developer and UI/UX Designer currently completing my Bachelor's degree in Information Technology at the International Islamic University Islamabad.
            </p>
            <p>
              I am a dedicated and enthusiastic Frontend Developer with a strong academic background in IT and a passion for crafting modern web applications. My experience includes developing AI-powered web applications, responsive user interfaces, and scalable frontend solutions.
            </p>
            <p>
              I believe that great software is built through collaboration, continuous learning, and attention to detail. My goal is to contribute to innovative projects where I can grow as a developer while creating impactful digital products.
            </p>
            <div className="about-info-grid">
              <div className="about-info-item">
                <span className="about-info-label">Full Name</span>
                <span className="about-info-value">Urwa Zareef</span>
              </div>
              <div className="about-info-item">
                <span className="about-info-label">Profession</span>
                <span className="about-info-value">Frontend Developer</span>
              </div>
              <div className="about-info-item">
                <span className="about-info-label">Location</span>
                <span className="about-info-value">Islamabad, Pakistan</span>
              </div>
              <div className="about-info-item">
                <span className="about-info-label">Email</span>
                <span className="about-info-value" style={{ fontSize: '0.82rem' }}>urwazareef4@gmail.com</span>
              </div>
              <div className="about-info-item">
                <span className="about-info-label">Phone</span>
