// ---- PROJECT MODAL ----
function ProjectModal({ project, onClose, projectImages, addProjectImage }) {
  const imgs = projectImages[project.id] || [];
  const fileRef = useRef();

  const handleAddImg = () => fileRef.current && fileRef.current.click();
  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => addProjectImage(project.id, ev.target.result);
    reader.readAsDataURL(file);
    e.target.value = '';
  };

  useEffect(() => {
    const handler = (e) => { if (e.key === 'Escape') onClose(); };
    document.addEventListener('keydown', handler);
    document.body.style.overflow = 'hidden';
    return () => { document.removeEventListener('keydown', handler); document.body.style.overflow = ''; };
  }, [onClose]);

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal-box">
        <div className="modal-header">
          <h2>{project.title}</h2>
          <button className="modal-close" onClick={onClose}>✕</button>
        </div>
        <div className="modal-body">
          <div className="modal-gallery">
            {imgs.map((src, i) => (
              <div key={i} className="gallery-item">
                <img src={src} alt={`Screenshot ${i + 1}`} />
              </div>
            ))}
            <div className="gallery-item" style={{ minHeight: 100 }}>
              <button className="gallery-add-btn" onClick={handleAddImg} style={{ width: '100%', border: 'none', borderRadius: 0 }}>
                <Icon d={ICONS.plus} size={22} />
                <span>Add Screenshot</span>
              </button>
            </div>
          </div>
          <input type="file" accept="image/*" className="hidden-input" ref={fileRef} onChange={handleFileChange} />

          <div className="modal-project-info">
            <div className="modal-tech-tags">
              {project.tags.map((t, i) => <span key={i} className="modal-tech-tag">{t}</span>)}
            </div>
            <p>{project.fullDesc}</p>
            <div className="modal-features">
              <h4>Key Features</h4>
              <ul>
                {project.features.map((f, i) => <li key={i}>{f}</li>)}
              </ul>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ---- PROJECTS ----
function Projects({ projectImages, addProjectImage, addProjectCardImage }) {
  const [modal, setModal] = useState(null);
  const fileRefs = useRef({});

  const openCardUpload = (id, e) => {
    e.stopPropagation();
    if (!fileRefs.current[id]) return;
    fileRefs.current[id].click();
  };
  const handleCardFile = (id, e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => addProjectCardImage(id, ev.target.result);
    reader.readAsDataURL(file);
    e.target.value = '';
  };

  return (
    <section id="projects" className="section section-alt">
      <div className="container">
        <div className="projects-header">
          <div>
            <div className="section-label">Portfolio</div>
            <h2 className="section-heading" style={{ marginBottom: 0 }}>
