          </div>
          <a href="#contact" className="btn btn-primary">View All Projects <Icon d={ICONS.arrow} size={15} /></a>
        </div>
        <div className="projects-grid">
          {projects.map(project => {
            const cardImg = (projectImages[`card_${project.id}`] || [])[0];
            return (
              <div key={project.id} className="project-card" onClick={() => setModal(project)}>
                <div className="project-img">
                  {cardImg
                    ? <img src={cardImg} alt={project.title} />
                    : (
                      <div className="project-img-placeholder">
                        <Icon d={ICONS.layout} size={36} />
                        <p>Click card to view gallery</p>
                      </div>
                    )}
                  <div className="project-overlay">
                    <button className="overlay-btn" onClick={e => { e.stopPropagation(); setModal(project); }}>
                      <Icon d={ICONS.eye} size={14} /> View Gallery
                    </button>
                    <button className="upload-overlay-btn" onClick={e => openCardUpload(project.id, e)}>
                      <Icon d={ICONS.camera} size={14} /> Upload Cover
                    </button>
                  </div>
                  <input
