                    className="hidden-input"
                    ref={el => fileRefs.current[project.id] = el}
                    onChange={e => handleCardFile(project.id, e)}
                  />
                </div>
                <div className="project-tags">
                  {project.featured && <span className="project-tag featured">⭐ Featured</span>}
                  {project.tags.slice(0, 3).map((t, i) => <span key={i} className="project-tag">{t}</span>)}
                </div>
                <div className="project-info">
                  <h3>{project.title}</h3>
                  <p>{project.desc}</p>
                </div>
              </div>
            );
          })}

          {/* Placeholder cards for future projects */}
          {[2, 3].map(n => (
            <div key={n} className="project-card" style={{ opacity: 0.6, cursor: 'default' }}>
              <div className="project-img">
                <div className="project-img-placeholder">
                  <Icon d={ICONS.plus} size={32} />
                  <p>Coming Soon</p>
                </div>
              </div>
              <div className="project-tags">
                <span className="project-tag">React.js</span>
                <span className="project-tag">JavaScript</span>
              </div>
              <div className="project-info">
                <h3>New Project {n}</h3>
                <p>Another exciting project coming soon. Stay tuned!</p>
              </div>
            </div>
          ))}
        </div>
      </div>
      {modal && (
        <ProjectModal
          project={modal}
          onClose={() => setModal(null)}
          projectImages={projectImages}
          addProjectImage={addProjectImage}
        />
      )}
    </section>
  );
}

