// ---- BACK TO TOP ----
function BackToTop() {
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const handler = () => setVisible(window.scrollY > 400);
    window.addEventListener('scroll', handler);
    return () => window.removeEventListener('scroll', handler);
  }, []);
  return (
    <button className={`back-to-top${visible ? ' visible' : ''}`} onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })} title="Back to top">
      <Icon d={ICONS.up} size={20} />
    </button>
  );
}

// ---- APP ----
export default function App() {
  const [dark, setDark] = useState(false);
  const [activeSection, setActiveSection] = useState('home');
  const [projectImages, setProjectImages] = useState({});

  const heroImg = useImageUpload();
  const aboutImg = useImageUpload();

  // Dark mode
  useEffect(() => {
    document.documentElement.setAttribute('data-theme', dark ? 'dark' : 'light');
  }, [dark]);

  // Active section tracking
  useEffect(() => {
    const sections = ['home', 'services', 'about', 'skills', 'projects', 'experience', 'contact'];
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) setActiveSection(entry.target.id);
        });
      },
      { threshold: 0.4 }
    );
    sections.forEach(id => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });
    return () => observer.disconnect();
  }, []);

  const addProjectImage = useCallback((projectId, src) => {
    setProjectImages(prev => ({
      ...prev,
      [projectId]: [...(prev[projectId] || []), src],
    }));
  }, []);

  const addProjectCardImage = useCallback((projectId, src) => {
    setProjectImages(prev => ({
      ...prev,
      [`card_${projectId}`]: [src],
    }));
  }, []);

  return (
    <div>
      <Navbar dark={dark} toggleDark={() => setDark(d => !d)} activeSection={activeSection} />
      <Hero heroImg={heroImg} />
      <Marquee />
      <Services />
      <About aboutImg={aboutImg} />
      <Skills />
      <Projects
        projectImages={projectImages}
        addProjectImage={addProjectImage}
        addProjectCardImage={addProjectCardImage}
      />
      <Experience />
      <Contact />
      <Footer />
      <BackToTop />
    </div>
  );
}
